/**
 * Shared bash snippets reused across flows. When the same shell incantation
 * appears in multiple flows (notably the codex-only `BITFAB_PLUGIN_DIR`
 * resolver), declare it here so the two flows stay in sync.
 *
 * If you change a snippet here, every flow that embeds it picks up the new
 * version on the next build.
 */
/**
 * Codex-only preamble: resolve `BITFAB_PLUGIN_DIR` if it isn't already
 * exported. Auto-detects dev / prod / custom-`CODEX_HOME` installs and exits
 * with an explicit error when the plugin isn't installed at all.
 *
 * Used by the codex `resolve-plugin-dir` step in `update` and `improve`.
 * (`setup` ships a slightly different variant inline — it adds a
 * `Found: …` success echo and skips the `if [ -z … ]` guard since setup is
 * the one entry point where re-resolution is expected to be a no-op.)
 *
 * Embedded inside a fenced ```bash code block — wrapping prose lives in the
 * step body so each flow can frame it with its own lead-in sentence.
 */
export const CODEX_RESOLVE_PLUGIN_DIR_BASH = `\`\`\`bash
if [ -z "$BITFAB_PLUGIN_DIR" ]; then
  BITFAB_PLUGIN_DIR=$(
    hit=$(find "\${CODEX_HOME:-$HOME/.codex}/plugins/cache" -maxdepth 6 -type f -name status.js \\
      \\( -path '*/bitfab-dev/bitfab/local/dist/commands/*' \\
      -o -path '*/bitfab/bitfab/*/dist/commands/*' \\) 2>/dev/null | head -1)
    echo "\${hit%/dist/commands/status.js}"
  )
  export BITFAB_PLUGIN_DIR
fi
test -n "$BITFAB_PLUGIN_DIR" || { echo "ERROR: Bitfab plugin not installed"; exit 1; }
\`\`\``;
